def go_to_item_to_pickup(self):
    level = self.agent.current_level()
    dis = self.agent.bfs()

    mask = dis > 0
    mask[mask] = np.vectorize(len)(self.agent.current_level().items[mask]) != 0

    items = {}
    for y, x in sorted(zip(*mask.nonzero()), key=lambda p: dis[p]):
        for i in level.items[y, x]:
            assert i not in items
            items[i] = (y, x)

    if not items:
        yield False  # TODO: what about just dropping items?

    free_items = list(filter(Item.can_drop_from_inventory, self.items))
    forced_items = list(filter(lambda i: not Item.can_drop_from_inventory(i), self.items))
    counts = self.agent.global_logic.item_priority.split(
            free_items + list(items.keys()), forced_items,
            self.agent.character.carrying_capacity)

    counts = counts[len(free_items):]
    assert len(counts) == len(items)
    if sum(counts) == 0:
        yield False
    yield True

    for i, c in zip(items, counts):
        if c != 0:
            target_y, target_x = items[i]
            break
    else:
        assert 0

    with self.agent.env.debug_tiles(mask, color=(255, 0, 0, 128)):
        self.agent.go_to(target_y, target_x, debug_tiles_args=dict(color=(255, 0, 255), is_path=True))

def main(self):
    self.update({k: v.copy() for k, v in self.env.reset().items()})
    self.current_level().stair_destination[self.blstats.y, self.blstats.x] = \
            ((Level.PLANE, 1), (None, None)) # TODO: check level num
    self.character.parse()
    self.character.parse_enhance_view()

    try:
        self.step(A.Command.AUTOPICKUP)

        inactivity_counter = 0
        last_turn = 0
        while 1:
            assert inactivity_counter < 100
            if last_turn != self.blstats.time:
                last_turn = self.blstats.time
                inactivity_counter = 0
            else:
                inactivity_counter += 1

            try:
                self.on_panic()

                self.step(A.Command.ESC)
                self.step(A.Command.ESC)
                self.check_terrain()

                self.global_logic.global_strategy().run()
                assert 0
            except AgentPanic as e:
                self.all_panics.append(e)
                if self.verbose:
                    print(f'PANIC!!!! : {e}')
            except AgentFinished:
                raise
            except KeyboardInterrupt:
                raise
            except BaseException as e:
                if not self.panic_on_errors:
                    raise
                self.all_panics.append(e)
                if self.verbose:
                    print(f'PANIC!!!! : {e}')
    except AgentFinished:
        pass

def get_message_and_popup(self, obs):
    """ Uses MORE action to get full popup and/or message.
    """
    # TODO: rethink recursion from calling step
    message = bytes(obs['message']).decode()
    popup = []
    is_extended_message = False
    while b'--More--' in bytes(obs['tty_chars'].reshape(-1)):
        assert not is_extended_message
        for i, line in enumerate(obs['tty_chars']):
            line = bytes(line)
            if b'--More--' not in line:
                continue
            if i == 0:
                message = line.decode()
                is_extended_message = True
            else:
                popup_start_column = line.find(b'--More--')
                for line in obs['tty_chars'][:i]:
                    line = bytes(line)
                    # TODO: consider cutting line suffix (check if it is always of the same length)
                    popup.append(line[popup_start_column:].decode().strip())
                break
        self.step(A.MiscAction.MORE)
        obs = self.last_observation

    if message == bytes([0] * 256).decode():
        message = ""

    if popup and message:
        raise ValueError(f'Either message ({str(message)}) or popup ({str(popup)}) should be empty')

    return message, popup
